using System.Globalization;
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Parse CSV manually so "Yes"/"No" maps correctly to bool
var rows = File.ReadLines(dataPath)
    .Skip(1)
    .Select(line =>
    {
        var p = line.Split(',');
        return new CustomerData
        {
            Age = float.Parse(p[0], CultureInfo.InvariantCulture),
            Income = float.Parse(p[1], CultureInfo.InvariantCulture),
            Region = p[2].Trim(),
            PurchaseHistory = float.Parse(p[3], CultureInfo.InvariantCulture),
            Churned = p[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase),
        };
    })
    .ToList();

var dataView = mlContext.Data.LoadFromEnumerable(rows);
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate(
        "Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on held-out test set (may fail with very small datasets)
try
{
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                      $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Model trained — test set too small for reliable metrics. Add more data.");
}

// Save model & register pooled prediction engine (thread-safe)
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
    };

    var result = pool.Predict(input);
    return Results.Ok(new
    {
        Churned = result.Churned,
        Probability = Math.Round(result.Probability, 4),
    });
});

app.Run();

public sealed record CustomerPredictRequest(
    float Age, float Income, string Region, float PurchaseHistory);

